import React from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function SugarMonitor(){

    const navigate=useNavigate();
        function goToDashboard() {
                    navigate('/dashboard');
        }

    return(
        <>
            <h1 className="l2container"> If you had a sugar test recently then enter your sugar test results </h1><br/>
            <br/>
            <form className="signcontainer">
                <br/><label htmlFor="beforeMeal">Enter Sugar Levels Before Meal:</label><br/>
                <input type="text" name="username" id="username"/><br/><br/>
                <label htmlFor="password">Enter Sugar Levels Afer Meal:</label><br/>
                <input type="text" name="password" id="password"/><br/><br/>
                <button onClick={goToDashboard()}>Add</button>
            </form>
        </>
        
    );
}

export default SugarMonitor;
